import React, { useState, useContext, useEffect } from 'react';
import { BrowserRouter, Routes, Route, useNavigate, Link } from 'react-router-dom';
import Navbar from './nav/Navbar';
import { AuthCtx } from './context/AuthContext';
import PageWrapper from './components/PageWrapper';
import ProtectedRoute from './components/ProtectedRoute';
import ScrollToTop from './components/ScrollToTop';
import LoadingSpinner from './components/LoadingSpinner';
import './App.css';
import './style.css';
import './webdesign.css';

const API_BASE = 'http://localhost:8080/api';

const Home = () => {
  const navigate = useNavigate();
  const { authToken } = useContext(AuthCtx);
  return (
    <PageWrapper>
      <section id="home-section">
        <div className="hero-section">
          <div className="badge">
            <span style={{marginRight: '8px'}}>✔</span>Democratic Voting Made Simple
          </div>
          <h1>Secure Online Voting Platform <span>for Modern Organizations</span></h1>
          <p>Empower your organization with transparent, secure, and accessible voting technology. From corporate decisions to community elections—all in one platform.</p>
          <p style={{fontSize: '0.95rem'}}>Our platform combines military-grade encryption, blockchain verification, and intuitive design to ensure every vote is counted securely and accurately. Whether you're running corporate elections, student body votes, or community referendums, VoteForChange provides the tools you need for transparent, accessible, and fraud-free elections.</p>
          <div className="hero-buttons">
            <button className="btn-primary" onClick={() => navigate(authToken ? '/dashboard' : '/signup')}>Start Voting Now</button>
            <button className="btn-secondary" onClick={() => navigate('/Service')}>Learn More</button>
          </div>
        </div>
      </section>
    </PageWrapper>
  );
};

const Features = () => (
  <PageWrapper>
    <section id="features-section" className="features-container">
      <h2>Powerful Features</h2>
      <p className="subtitle">Secure - Swift - Simple | Everything for Modern Elections</p>
      <div className="features-grid">
        <div className="feature-card"><div className="feature-icon">🔒</div><h3>End-to-End Encryption</h3><p>Military-grade encryption ensures your votes are completely secure and private.</p></div>
        <div className="feature-card"><div className="feature-icon">📱</div><h3>Mobile Accessible</h3><p>Vote from any device - smartphones, tablets, or desktops with seamless experience.</p></div>
        <div className="feature-card"><div className="feature-icon">⚡</div><h3>Real-Time Analytics</h3><p>Live voting statistics and instant result visualization for election organizers.</p></div>
        <div className="feature-card"><div className="feature-icon">🎯</div><h3>Precise Vote Counting</h3><p>Accurate vote counting with blockchain verification for complete transparency.</p></div>
        <div className="feature-card"><div className="feature-icon">🌍</div><h3>Global Accessibility</h3><p>Support for 50+ languages and international standards.</p></div>
