const Login = () => {
  const { login } = useContext(AuthCtx);
  const navigate = useNavigate();
  const [id, setId] = useState('');
  const [pwd, setPwd] = useState('');
  const [err, setErr] = useState('');

  const handleLogin = async () => {
    try {
      const res = await fetch(`${API_BASE}/auth/login`, {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({emailOrVoterId: id, password: pwd})
      });
      const data = await res.json();
      if(res.ok) {
        login(data.token, data.voterId);
        localStorage.setItem('role', data.role);
        navigate('/dashboard');
      } else {
        setErr('Invalid credentials');
      }
    } catch (e) {
      setErr('Server error');
    }
  };

  return (
    <PageWrapper>
      <section id="auth-section">
        <div className="auth-card">
          <h2>Login</h2>
          <div className="input-group"><label>Voter ID:</label><input value={id} onChange={e=>setId(e.target.value)} type="text" placeholder="e.g., ABC1234567 or Email" /></div>
          <div className="input-group"><label>Password:</label><input value={pwd} onChange={e=>setPwd(e.target.value)} type="password" placeholder="Enter your password" /></div>
          <button onClick={handleLogin} className="btn-primary" style={{marginTop: '10px'}}>Sign In</button>
          <p className="error-msg">{err}</p>
          <div className="auth-switch">Don't have an account? <Link to="/signup">Sign up</Link></div>
        </div>
      </section>
    </PageWrapper>
  );
};

const Signup = () => {
  const navigate = useNavigate();
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [pwd, setPwd] = useState('');
  const [err, setErr] = useState('');
  const [succ, setSucc] = useState('');

  const handleRegister = async () => {
    try {
      const res = await fetch(`${API_BASE}/auth/register`, {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({name, email, password: pwd})
      });
      const data = await res.json();
      if(res.ok) {
        setSucc(`Successfully registered! Your Voter ID is ${data.voterId}. Please login.`);
        setErr('');
      } else {
        setErr(data.message || 'Registration failed');
      }
    } catch (e) {
      setErr('Server error');
    }
  };

  return (
    <PageWrapper>
      <section id="auth-section">
        <div className="auth-card">
          <h2>Sign Up</h2>
          <div className="input-group"><label>Name:</label><input value={name} onChange={e=>setName(e.target.value)} type="text" placeholder="Enter your Name" /></div>
          <div className="input-group"><label>Voter ID:</label><input type="text" placeholder="e.g., ABC1234567 (Auto-generated on register)" disabled style={{background: '#f8f9fa'}} /></div>
          <div className="input-group"><label>Email:</label><input value={email} onChange={e=>setEmail(e.target.value)} type="email" placeholder="Enter your Email" /></div>
          <div className="input-group"><label>Password:</label><input value={pwd} onChange={e=>setPwd(e.target.value)} type="password" placeholder="Enter your Password" /></div>
          <button onClick={handleRegister} className="btn-primary" style={{marginTop: '10px'}}>Create Account</button>
          <p className="error-msg">{err}</p>
          <p className="error-msg" style={{color: '#10b981'}}>{succ}</p>
          <div className="auth-switch">Already have an account? <Link to="/Login">Login</Link></div>
