const Voting = () => {
  const { authToken } = useContext(AuthCtx);
  const [cands, setCands] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch(`${API_BASE}/candidates`, { headers: {'Authorization': `Bearer ${authToken}`} })
      .then(r => r.json()).then(d => { setCands(d); setLoading(false); }).catch(()=>setLoading(false));
  }, [authToken]);

  const castVote = async (id) => {
    if(!window.confirm('Are you sure? You can only vote once.')) return;
    const res = await fetch(`${API_BASE}/vote`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${authToken}` },
      body: JSON.stringify({candidateId: id})
    });
    if(res.ok) { alert('Vote cast successfully!'); window.location.href='/dashboard'; }
    else alert('Error: You may have already voted.');
  };

  return (
    <PageWrapper>
      <section id="voting-section" style={{background: 'var(--card-bg)', padding: '40px', borderRadius: '12px', boxShadow: '0 10px 40px rgba(0,0,0,0.08)', width: '100%', maxWidth: '800px', margin: '40px auto'}}>
        <h2 style={{textAlign:'center'}}>Candidate Selection</h2>
        <p style={{textAlign: 'center', marginBottom: '20px', color: 'var(--text-muted)'}}>Please select your preferred candidate carefully. You can only vote once.</p>
        {loading ? <LoadingSpinner /> : (
          <div className="candidates-grid" style={{display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px'}}>
            {cands.map(c => (
              <div key={c.id} className="candidate-card" style={{background: 'var(--bg-main)', padding: '20px', borderRadius: '12px', textAlign: 'center', border: '1px solid #e0e0e0'}}>
                <div className="candidate-name" style={{fontSize: '1.2rem', fontWeight: 'bold', marginBottom: '5px', color: 'var(--text-dark)'}}>{c.name}</div>
                <div className="candidate-party" style={{color: 'var(--text-muted)', fontSize: '0.9rem', marginBottom: '15px'}}>{c.party}</div>
                <button className="btn-primary" onClick={() => castVote(c.id)}>Vote</button>
              </div>
            ))}
          </div>
        )}
      </section>
    </PageWrapper>
  );
};

const Admin = () => {
  const { authToken } = useContext(AuthCtx);
  const [res, setRes] = useState([]);
  const [name, setName] = useState('');
  const [party, setParty] = useState('');

  const load = () => {
    fetch(`${API_BASE}/admin/results`, { headers: {'Authorization': `Bearer ${authToken}`} })
      .then(r => r.json()).then(d => setRes(d));
  };
  useEffect(load, [authToken]);

  const add = async () => {
    if(!name || !party) return;
    const response = await fetch(`${API_BASE}/admin/add-candidate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${authToken}` },
      body: JSON.stringify({name, party})
    });
    if(response.ok) { setName(''); setParty(''); load(); }
  };

  const del = async (id) => {
    await fetch(`${API_BASE}/admin/delete-candidate/${id}`, { method: 'DELETE', headers: {'Authorization': `Bearer ${authToken}`} });
    load();
  };

  return (
    <PageWrapper>
      <section id="admin-section" style={{background: 'var(--card-bg)', padding: '40px', borderRadius: '12px', boxShadow: '0 10px 40px rgba(0,0,0,0.08)', width: '100%', maxWidth: '800px', margin: '40px auto'}}>
        <h2 style={{textAlign:'center'}}>Admin Panel - Live Results</h2>
        <div className="admin-controls" style={{display: 'flex', gap: '10px', marginBottom: '20px'}}>
          <input value={name} onChange={e=>setName(e.target.value)} type="text" placeholder="Candidate Name" style={{flex:1, padding:'10px', borderRadius:'8px', border:'1px solid #e0e0e0'}} />
          <input value={party} onChange={e=>setParty(e.target.value)} type="text" placeholder="Party Name" style={{flex:1, padding:'10px', borderRadius:'8px', border:'1px solid #e0e0e0'}} />
          <button onClick={add} className="btn-primary" style={{width: 'auto', whiteSpace: 'nowrap'}}>Add Candidate</button>
        </div>
        <div className="results-list" style={{display: 'flex', flexDirection: 'column', gap: '15px'}}>
          {res.map(c => (
            <div key={c.id} className="result-item" style={{background: 'var(--bg-main)', padding: '15px 20px', borderRadius: '8px', border: '1px solid #e0e0e0', display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
              <div><strong>{c.name}</strong> ({c.party}) <br/><span style={{color: 'var(--primary-color)'}}>Votes: {c.votes}</span></div>
              <button onClick={() => del(c.id)} style={{width: 'auto', background: 'var(--danger)', color:'white', border:'none', padding:'8px 16px', borderRadius:'8px', cursor:'pointer'}}>Delete</button>
            </div>
          ))}
        </div>
      </section>
    </PageWrapper>
  );
};

